// FindProjectRoot walks up from startDir to find the git repository root.
// It returns the top-level directory of the git working tree. If startDir
// is not inside a git repository, it returns startDir unchanged.
//
// This is analogous to `git rev-parse --show-toplevel` and ensures that
// ddx always operates from the repository root regardless of the caller's
// working directory. Without this, running `ddx` from a subdirectory that
// contains its own `.ddx/` folder would silently use the wrong workspace.
func FindProjectRoot(startDir string) string {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	cmd := Command(ctx, startDir, "rev-parse", "--show-toplevel")
	out, err := cmd.Output()
	if err != nil {
		// Not in a git repo — fall back to the original directory.
		return startDir
	}
	root := strings.TrimSpace(string(out))
	if root == "" {
		return startDir
	}
	if physical := physicalGitRoot(startDir); physical != "" && !samePath(physical, root) {
		return physical
	}
	return root
}

// physicalGitRoot walks upward on disk until it finds a .git directory or
// linked-worktree .git file. This intentionally bypasses git's configured
// worktree resolution so a corrupted local core.worktree cannot redirect ddx
// away from the checkout the operator actually invoked.
func physicalGitRoot(startDir string) string {
	current, err := filepath.Abs(startDir)
	if err != nil {
		return ""
	}
	for {
		if _, statErr := os.Stat(filepath.Join(current, ".git")); statErr == nil {
			return current
		}
		parent := filepath.Dir(current)
		if parent == current {
			return ""
		}
		current = parent
	}
}

func samePath(a, b string) bool {
	if a == "" || b == "" {
		return false
	}
	cleanA, err := filepath.Abs(a)
	if err != nil {
		cleanA = filepath.Clean(a)
	}
	cleanB, err := filepath.Abs(b)
	if err != nil {
		cleanB = filepath.Clean(b)
	}
	if resolvedA, err := filepath.EvalSymlinks(cleanA); err == nil {
		cleanA = resolvedA
	}
	if resolvedB, err := filepath.EvalSymlinks(cleanB); err == nil {
		cleanB = resolvedB
	}
	return cleanA == cleanB
}

// FindNearestDDxWorkspace walks up from startDir to find the nearest ancestor
// inside the current git repository that contains a .ddx workspace.
//
// When startDir is inside a linked git worktree (e.g. an execute-bead
// isolated worktree under .ddx/.execute-bead-wt-* or a worktrunk sibling
// like repo.feature-branch/), it resolves to the PRIMARY worktree's .ddx/
// first, not the linked worktree's own .ddx/. This is critical because:
//
//   - bead store mutations must land in the canonical project bead queue,
//     not in an isolated worktree's private snapshot that will be discarded
//   - the primary worktree is the operator's source of truth; linked
//     worktrees are ephemeral execution contexts
//
// If the primary worktree has no .ddx/ (or we aren't in a linked worktree),
// it falls back to walking up from startDir within the current git
// repository.
//
// Returns an empty string if no .ddx/ is found.
func FindNearestDDxWorkspace(startDir string) string {
	abs, err := filepath.Abs(startDir)
	if err != nil {
		return ""
	}

	// If we're inside a linked worktree, prefer the primary worktree's .ddx/.
	if primary := primaryWorktreeRoot(abs); primary != "" && primary != FindProjectRoot(abs) {
		candidate := filepath.Join(primary, ".ddx")
		if info, statErr := os.Stat(candidate); statErr == nil && info.IsDir() {
			return primary
		}
	}

	gitRoot := FindProjectRoot(abs)
	current := abs
	for {
		candidate := filepath.Join(current, ".ddx")
		if info, statErr := os.Stat(candidate); statErr == nil && info.IsDir() {
			return current
		}
		if current == gitRoot {
			break
		}
		parent := filepath.Dir(current)
		if parent == current {
			break
		}
		current = parent
	}
	return ""
}

// IsRepository checks if the current directory is a git repository.
func IsRepository(path string) bool {
	if path == "" {
		path = "."
	}

	cleanPath := filepath.Clean(path)
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	cmd := Command(ctx, cleanPath, "rev-parse", "--git-dir")
	return cmd.Run() == nil
}

// primaryWorktreeRoot returns the primary (non-linked) worktree directory
// for a given path inside a git repository, or "" if the path is not inside
// a linked worktree (or if resolution fails).
//
// Detection: `git rev-parse --git-common-dir` returns the shared .git
// directory. If that differs from `git rev-parse --git-dir`, we're in a
// linked worktree. The primary worktree is the parent directory of the
// common .git dir (unless the shared dir is a bare repo).
func primaryWorktreeRoot(startDir string) string {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	gitDirCmd := Command(ctx, startDir, "rev-parse", "--path-format=absolute", "--git-dir")
	gitDirOut, err := gitDirCmd.Output()
	if err != nil {
		return ""
	}
	gitDir := strings.TrimSpace(string(gitDirOut))

	commonDirCmd := Command(ctx, startDir, "rev-parse", "--path-format=absolute", "--git-common-dir")
	commonDirOut, err := commonDirCmd.Output()
	if err != nil {
		return ""
	}
	commonDir := strings.TrimSpace(string(commonDirOut))

	if gitDir == commonDir {
		// Not a linked worktree.
		return ""
	}

	// Common dir is either a bare repo or the primary worktree's .git dir.
	// If it's a .git directory, the primary worktree is its parent.
	if filepath.Base(commonDir) == ".git" {
		return filepath.Dir(commonDir)
	}
	// Bare repo: no primary worktree. Caller falls back to walk-up.
	return ""
}

		return
	}

	// Load config
	cfg, err := config.Load()
	if err != nil {
		// Silent failure - use defaults
		cfg = config.DefaultNewConfig()
	}

	// Check if disabled via config
	if cfg.UpdateCheck != nil && !cfg.UpdateCheck.Enabled {
		return
	}

	// Create checker and perform check (synchronous)
	checker := update.NewChecker(f.Version, cfg)
	f.updateMu.Lock()
	f.updateChecker = checker
	f.updateDone = make(chan struct{})
	done := f.updateDone
	f.updateMu.Unlock()

	// Run the check asynchronously so command startup is never blocked.
	go func() {
		defer close(done)
		_, _ = checker.CheckForUpdate(context.Background())
		// Also refresh plugin version cache while we have a network call in flight.
		f.refreshPluginVersionCache()
	}()
}

// displayUpdateNotification shows update notification if available
func (f *CommandFactory) displayUpdateNotification(cmd *cobra.Command) error {
	// Skip if disabled via environment variable
	if os.Getenv("DDX_DISABLE_UPDATE_CHECK") == "1" {
		return nil
	}

	f.updateMu.Lock()
	checker := f.updateChecker
	done := f.updateDone
	f.updateMu.Unlock()

	if checker == nil {
		return nil
	}

	if done != nil {
		select {
		case <-done:
		default:
			return nil
		}
	}

	// Skip update notification for help commands
	if cmd.Name() == "help" || cmd.Parent() != nil && cmd.Parent().Name() == "help" {
		return nil
	}

	// Skip update notification for machine-readable output formats
	jsonFlag, _ := cmd.Flags().GetBool("json")
	if jsonFlag {
		return nil
	}

	// Skip update notification if silent flag is set
	silentFlag, _ := cmd.Flags().GetBool("silent")
	if silentFlag {
		return nil
	}

	// Skip update notification if --no-check flag is set (for version command)
	noCheck, _ := cmd.Flags().GetBool("no-check")
	if noCheck {
		return nil
	}

	// Skip when stdout is not a terminal (pipes, scripts, CI)
	if !isatty.IsTerminal(os.Stdout.Fd()) && !isatty.IsCygwinTerminal(os.Stdout.Fd()) {
		return nil
	}

	available, version, err := checker.IsUpdateAvailable()
	if err != nil || !available {
		if err != nil {
			_, _ = fmt.Fprintf(os.Stderr, "Warning: Could not check for updates: %v\n", err)
		}
		return nil
	}

	// Show update notification with changelog for version command
	// Always write to stderr so it doesn't corrupt JSON pipelines
	isVersionCmd := cmd.Use == "version"
	if isVersionCmd {
		_, _ = fmt.Fprintf(os.Stderr,
			"\n⬆️  Update available: %s (run 'ddx upgrade' to install)\n\nWhat's new:\n  • Performance improvements\n  • Bug fixes\n  • New features\n",
			version)
	} else {
		_, _ = fmt.Fprintf(os.Stderr,
			"\n⬆️  Update available: %s (run 'ddx upgrade' to install)\n",
			version)
	}

	return nil
}

// checkVersionGate blocks execution if the binary is older than the project requires.
// Returns an error for non-exempt commands when binary version < project's ddx_version.
func (f *CommandFactory) checkVersionGate(cmd *cobra.Command) error {
	// Dev builds bypass the gate
	if f.Version == "" || f.Version == "dev" {
		return nil
	}

	// Read project versions
	projectVersion := readProjectVersions(f.WorkingDir)
	if projectVersion == "" || projectVersion == "dev" {
		return nil // No versions.yaml or dev project — skip
	}

	// Exempt commands that must work even when binary is too old
	switch cmd.Name() {
	case "upgrade", "version", "doctor", "init", "help", "completion":
		return nil
	}

	// Compare: is the binary older than what the project requires?
	needsUpgrade, err := update.NeedsUpgrade(f.Version, projectVersion)
	if err != nil {
		return nil // Parse error — don't block
	}
	if needsUpgrade {
		return fmt.Errorf("this project requires DDx v%s or newer (you have %s).\nRun 'ddx upgrade' to update your DDx binary",
			strings.TrimPrefix(projectVersion, "v"),
			f.Version)
	}

	return nil
}

// displayStalenessHints shows soft hints when project skills or plugins are outdated.
func (f *CommandFactory) displayStalenessHints(cmd *cobra.Command) {
	// Skip for machine-readable output
	if jsonFlag, _ := cmd.Flags().GetBool("json"); jsonFlag {
		return
	}
	if silentFlag, _ := cmd.Flags().GetBool("silent"); silentFlag {
		return
	}
	// Skip when stdout is not a terminal (pipes, scripts, CI)
	if !isatty.IsTerminal(os.Stdout.Fd()) && !isatty.IsCygwinTerminal(os.Stdout.Fd()) {
		return
	}

	// Dev builds don't hint
	if f.Version == "" || f.Version == "dev" {
		return
	}

